        else {
            this.getLeaders(this.state.number_limit, e.target.value);
            this.setState({ time_limit: e.target.value });
        }
    }
    componentDidMount() {
        this.getLeaders(this.state.number_limit, this.state.time_limit);
    }
    getLeaders(number_limit, time_limit) {
