        });
        fetch(`/api/leaderboard/leaders?number_limit=${number_limit}&time_limit=${time_limit}`).then((res) => res.json()).then((data) => {
            if (data && data.leaders) {
                this.setState({
                    leaders: data.leaders,
                    fetching: false
